import{_ as a,o as r,c as e,ai as d}from"./chunks/framework.SowO7O0D.js";const b=JSON.parse('{"title":"第一课：股票是什么？","description":"","frontmatter":{},"headers":[],"relativePath":"guide/01-what-is-stock.md","filePath":"guide/01-what-is-stock.md","lastUpdated":0}'),o={name:"guide/01-what-is-stock.md"};function l(i,t,h,n,s,c){return r(),e("div",null,[...t[0]||(t[0]=[d('<h1 id="第一课-股票是什么" tabindex="-1">第一课：股票是什么？ <a class="header-anchor" href="#第一课-股票是什么" aria-label="Permalink to “第一课：股票是什么？”">​</a></h1><h2 id="一句话理解" tabindex="-1">一句话理解 <a class="header-anchor" href="#一句话理解" aria-label="Permalink to “一句话理解”">​</a></h2><p><strong>股票就是上市公司的&quot;所有权凭证&quot;。</strong></p><p>买了哪家公司的股票，你就成了这家公司的&quot;小老板&quot;之一，持有它的股份。</p><h2 id="🏠-生活比喻" tabindex="-1">🏠 生活比喻 <a class="header-anchor" href="#🏠-生活比喻" aria-label="Permalink to “🏠 生活比喻”">​</a></h2><p>想象你和朋友合伙开了一家奶茶店：</p><ul><li>你出了 <strong>10万</strong>，朋友出了 <strong>10万</strong></li><li>你们各占 <strong>50% 股权</strong></li><li>这50%股权就是&quot;股票&quot;</li></ul><p>奶茶店生意好 → 你们按比例分红 奶茶店做大了要上市 → 你们的股权可以转让给别人变现</p><h2 id="📈-a股实例" tabindex="-1">📈 A股实例 <a class="header-anchor" href="#📈-a股实例" aria-label="Permalink to “📈 A股实例”">​</a></h2><table tabindex="0"><thead><tr><th>股票</th><th>代码</th><th>股价（约）</th><th>含义</th></tr></thead><tbody><tr><td>贵州茅台</td><td>600519</td><td>1700元/股</td><td>买1手（100股）= 17万，你就是中国最值钱白酒企业的小老板</td></tr><tr><td>宁德时代</td><td>300750</td><td>200元/股</td><td>买了它，就是新能源电池龙头的小老板</td></tr><tr><td>中国平安</td><td>601318</td><td>45元/股</td><td>买了它，就是中国最大保险公司的小老板</td></tr></tbody></table><h2 id="股票赚钱的两种方式" tabindex="-1">股票赚钱的两种方式 <a class="header-anchor" href="#股票赚钱的两种方式" aria-label="Permalink to “股票赚钱的两种方式”">​</a></h2><h3 id="_1-📈-差价收益-低买高卖" tabindex="-1">1. 📈 差价收益（低买高卖） <a class="header-anchor" href="#_1-📈-差价收益-低买高卖" aria-label="Permalink to “1. 📈 差价收益（低买高卖）”">​</a></h3><p>就像二手房买卖，你500元买的股票，涨到600元卖掉，赚100元差价。</p><blockquote><p><strong>注意</strong>：这是&quot;纸上富贵&quot;，卖掉之前只是数字。</p></blockquote><h3 id="_2-💰-分红收益-公司赚钱了分给你" tabindex="-1">2. 💰 分红收益（公司赚钱了分给你） <a class="header-anchor" href="#_2-💰-分红收益-公司赚钱了分给你" aria-label="Permalink to “2. 💰 分红收益（公司赚钱了分给你）”">​</a></h3><p>公司盈利后，会把一部分利润分给股东，这就是<strong>分红</strong>。</p><p>就像奶茶店今年赚了20万，你们决定把10万分掉，你拿5万。</p><blockquote><p><strong>A股分红举例</strong>：</p><ul><li>茅台每年分红约每股25元（2023年）</li><li>工商银行每年分红约每股0.3元（稳定但少）</li><li>长江电力每年分红约每股0.85元（公用事业，稳定）</li></ul></blockquote><h2 id="股票的本质" tabindex="-1">股票的本质 <a class="header-anchor" href="#股票的本质" aria-label="Permalink to “股票的本质”">​</a></h2><p>股票代表的是 <strong>公司的一部分价值</strong>，而不是一个简单的代码或价格。</p><p>一家好公司 → 长期来看 → 股价大概率上涨 一家差公司 → 长期来看 → 股价大概率下跌，甚至退市</p><p>所以炒股票，本质上是在判断：<strong>这家公司的价值，现在被市场高估了还是低估了？</strong></p><h2 id="关键指标速览" tabindex="-1">关键指标速览 <a class="header-anchor" href="#关键指标速览" aria-label="Permalink to “关键指标速览”">​</a></h2><table tabindex="0"><thead><tr><th>指标</th><th>含义</th><th>简单理解</th></tr></thead><tbody><tr><td>股价</td><td>当前每股价格</td><td>股票贵不贵</td></tr><tr><td>市值</td><td>总股本 × 股价</td><td>公司&quot;卖多少钱&quot;</td></tr><tr><td>PE（市盈率）</td><td>股价 ÷ 每股收益</td><td>回本要多少年</td></tr><tr><td>分红</td><td>公司给股东的现金</td><td>持有股票能拿多少</td></tr></tbody></table><h2 id="思考题" tabindex="-1">思考题 <a class="header-anchor" href="#思考题" aria-label="Permalink to “思考题”">​</a></h2><blockquote><p>如果你现在有10万元，有以下两个选择：</p><ol><li>存银行，年利率2%</li><li>买一只股票，假设每年分红4%</li></ol><p>你会怎么选？为什么？</p></blockquote><hr><p><strong>下一课预告</strong>：了解股票是什么之后，下一课我们来讲<strong>如何迈出第一步</strong>——去哪里开户，需要准备什么。</p>',28)])])}const u=a(o,[["render",l]]);export{b as __pageData,u as default};
